//vip.opstream15.com/20220413/3569_25b60857/index.m3u8"}]}],"description":"<p>Tiền kiếp và hiện tại hòa lẫn vào nhau, chàng trai với hai kí ức của hai kiếp người đứng lên chống lại định mệnh. Thuở thơ ấu, Rio đã sớm trở thành trẻ mồ côi do mẹ bị giết, cậu phải kiến cường sống sót trong khu ổ chuột. Một ngày nọ, chàng trai Amakawa Haruto đã chết trong một tai nạn trong lúc mơ về cuộc tái ngộ với cô bạn thuở nhỏ đã mất tích, thức tỉnh bên trong thân xác Rio cùng với nguồn ma lực khổng lồ. Lúc ấy Haruto nhận ra mình đã chuyển sinh tại dị giới của kiếm và ma thuật. Sau một lần vô tình góp phần giải quyết vụ án bắt cóc công chúa, Haruto được Quốc vương đặc cách cho nhập học tại Học viện Hoàng gia Beltram. Đây là câu chuyện về cậu nhóc Rio và cũng là chàng trai Amakawa Haruto leo lên từ dưới đáy xã hội, qua nhiều cuộc gặp gỡ và chia li, cậu tích lũy sức mạnh để đánh tan vận mệnh tàn khốc.</p>","tmdb_id":113808,"_supabaseOriginalSlug":"tinh-linh-huyen-tuong-ky","_supabaseExportEpisodesOnly":false,"_id":"6256e8d76c7fada3b6652872","time":"24 phút/tập","tmdb":{"type":"tv","id":"113808","season":1,"vote_average":8.3,"vote_count":240}},{"id":"6256e9b46c7fada3b6652922","title":"takt op.Destiny","origin_name":"takt op.Destiny","slug":"takt-opdestiny","_from_supabase":true,"year":"2021","type":"hoathinh","genre":[{"name":"Hành Động","slug":"hanh-djong"},{"name":"Viễn Tưởng","slug":"vien-tuong"},{"name":"Âm Nhạc","slug":"am-nhac"}],"country":[{"name":"Nhật Bản","slug":"nhat-ban"}],"lang_key":"Vietsub","episode_current":"Hoàn Tất (12/12)","quality":"HD","modified":"2026-03-30T06:39:10.633+00:00","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"name":"Vietsub #1","slug":"vietsub-1","server_name":"Vietsub #1","server_data":[{"name":"1","slug":"1","link_embed":"https://vip.opstream12.com/share/9a5b67bf56e576c4d0de7d90d3171644","link_m3u8":"https://vip.opstream12.com/20220413/10365_a9851dc5/index.m3u8"}]}],"descri